import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import api from "../services/api";
import styles from "../styles/Auth.module.css";

const RegisterPage = () => {
  const [formData, setFormData] = useState({ username: "", password: "", role: "USER" });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.post("/auth/register", formData);
      alert("Registro exitoso. Ahora inicia sesión.");
      navigate("/login");
    } catch (err) {
      setError("Error al registrarse. Prueba con otro usuario.");
    }
  };

  return (
    <div className={styles.container}>
      <h1 className={styles.title}>Reminders</h1>
      <div className={styles.card}>
        <h2 className={styles.cardTitle}>Crear Cuenta</h2>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            name="username"
            placeholder="Nuevo Usuario"
            onChange={handleChange}
            required
            className={styles.input}
          />
          <input
            type="password"
            name="password"
            placeholder="Contraseña"
            onChange={handleChange}
            required
            className={styles.input}
          />
          <select name="role" onChange={handleChange} className={styles.input} style={{appearance: "none"}}>
            <option value="USER">Usuario Normal</option>
            <option value="GESTOR">Gestor (Puede crear categorías)</option>
            <option value="ADMIN">Administrador</option>
          </select>
          <button type="submit" className={styles.button}>Registrarse</button>
        </form>
        {error && <p className={styles.error}>{error}</p>}
      </div>
      <div className={styles.linkContainer}>
        <Link to="/login">¿Ya tienes cuenta? Entra aquí</Link>
      </div>
    </div>
  );
};

export default RegisterPage;
